+#[cfg(all(target_os = "linux", feature = "io-uring"))]
+#[allow(unsafe_code)]
+fn uring_submit_one(entry: io_uring::squeue::Entry) -> io::Result<()> {
+    use io_uring::IoUring;
+
+    let mut ring = IoUring::new(2)?;
+    unsafe {
